    "SchemaDefinition": {
        "tenantId": "{{stateTenant}}",
        "code": "common-masters.MobileNumberValidation",
        "description": "Mobile Number Validation — single source of truth for mobile number regex and country code prefix. Keyed by countryCode. Consumed by useMobileValidation hooks in digit-ui and the configurator.",
        "isActive": true,
        "definition": {
            "$schema": "http://json-schema.org/draft-07/schema#",
            "title": "Mobile Number Validation",
            "type": "object",
            "required": [
                "countryCode",
                "mobileNumberRegex"
            ],
            "x-unique": [
                "countryCode"
            ],
            "properties": {
                "tenantId": {
                    "type": "string"
                },
                "countryCode": {
                    "type": "string",
                    "description": "Country dial code shown as prefix in the UI, e.g. +251 (Ethiopia), +91 (India), +254 (Kenya). Serves as the unique key — only one record per country code."
                },
                "mobileNumberRegex": {
                    "type": "string",
                    "description": "Full-anchor regex for the national number portion (digits only, without the country code), e.g. ^[79][0-9]{8}$ for Ethiopia (9 digits starting with 7 or 9)."
                },
                "default": {
                    "type": "boolean",
                    "default": false,
                    "description": "Whether this is the default validation rule for the deployment. Only one record should have default: true at a time."
                },
                "isActive": {
                    "type": "boolean",
                    "default": true,
                    "description": "Whether this rule is active. Inactive records (isActive: false) are ignored by the validation hooks and shown as disabled in the configurator."
                }
            },
            "x-ref-schema": [],
            "additionalProperties": false
        }
    }
}

